VALUES
  ('elementary-f29af906-moex-00508', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，重劃地區選定後，直轄市或縣（市）政府得視實際需要報經上級主管機關 核定後，公告禁止或限制一定事項。關於公告禁止或限制一定事項，下列選項何者錯誤？', '["公告禁止或限制事項，無須徵詢土地及建築改良物所有權人之同意", "禁止或限制之期間，不得超過2年", "可以禁止或限制土地移轉、分割或設定負擔", "可以禁止或限制建築改良物之新建、增建、改建或重建及採取土石或變更地形"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00509', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，實施市地重劃時，重劃區內供公共使用之十項用地，由參加重劃土地所有 權人按其土地受益比例共同負擔，並以重劃區內未建築土地折價抵付。下列選項，何者不屬於前述 之十項用地？', '["兒童遊樂場", "國民中學", "社會福利設施", "零售市場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00510', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於配偶相互贈與土地，依現行土地稅法之規定，下列敘述何者錯誤？', '["配偶相互贈與之土地，得申請不課徵土地增值稅", "配偶相互贈與之土地申請不課徵土地增值稅後，於再移轉第三人時，以該土地最近贈與時之公告 土地現值為原地價，計算漲價總數額，課徵土地增值稅", "配偶相互贈與之土地申請不課徵土地增值稅後，於再移轉依法應課徵土地增值稅時，以該土地第 一次不課徵土地增值稅前之原規定地價或最近一次課徵土地增值稅時核定之申報移轉現值為原地 價，計算漲價總數額，課徵土地增值稅", "配偶相互贈與之土地，於再移轉計課土地增值稅時，贈與人或受贈人於其具有土地所有權之期間 內，有支付第31條第1項改良土地之改良費用或同條第3項增繳之地價稅者，準用該條之減除或 抵繳規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00511', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法之規定，其施行細則，應由那一個機關定之？', '["行政院", "內政部", "財政部", "經濟部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00512', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法之規定，地價稅以何時為納稅義務基準日？', '["每年8月31日", "每年11月1日", "每年1月1日", "每年6月30日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00513', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法之規定，關於依法得徵收之私有土地，有關其移轉所涉土地增值稅之規定，下列敘述何 者錯誤？', '["依法得徵收之私有土地，土地所有權人自願售與需用土地人者，免徵其土地增值稅", "依都市計畫法指定之公共設施保留地尚未被徵收前之移轉，免徵土地增值稅", "都市計畫法指定之公共設施保留地經變更為非公共設施保留地後再移轉時，以該土地第一次免徵 土地增值稅前之原規定地價或最近一次課徵土地增值稅時核定之申報移轉現值為原地價，計算漲 價總數額，課徵土地增值稅", "非都市土地經需用土地人開闢完成或依計畫核定供公共設施使用，並依法完成使用地編定，其尚 未被徵收前之移轉，以該土地第一次免徵土地增值稅前之原規定地價或最近一次課徵土地增值稅 時核定之申報移轉現值為原地價，計算漲價總數額，課徵土地增值稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00514', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法之規定，經核定應徵空地稅之土地，按該宗土地應納地價稅基本稅額加徵多少倍數之空 地稅？', '["一至三倍", "二至五倍", "三至六倍", "四至八倍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00515', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依房屋稅條例之規定，私有房屋符合特定情形者，免徵房屋稅。下列敘述何者並非免徵房屋稅之 情形？', '["無償供政府機關公用或供軍用之房屋", "司法保護事業所有之房屋", "農會所有之自用倉庫及檢驗場，經主管機關證明者", "受重大災害，毀損面積佔整棟面積五成以上，必須修復始能使用之房屋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00516', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，下列關於規定地價或重新規定地價之敘述，何者正確？', '["規定地價後，每一年重新規定地價一次", "舉辦規定地價時，土地所有權人未於公告期間申報地價者，以公告地價百分之一百二十為其申報 地價", "已規定地價之土地，應按公告地價，依法徵收地價稅", "直轄市或縣（市）主管機關辦理規定地價或重新規定地價之程序中，公告及申報地價，其期限為 30日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00517', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例之規定，下列關於照價收買之敘述，何者錯誤？', '["照價收買之土地，地上建築改良物同屬土地所有權人所有者，應一併收買", "政府依法照價收買而取得之土地，得隨時公開出售，不受土地法第25條之限制", "照價收買之土地，地上如有農作改良物，應予補償", "依本條例照價收買土地所需之資金，得由土地銀行發行土地債券"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
